SELECT vm_name
FROM virtual_machines
WHERE memory_size = (SELECT MAX(memory_size) FROM virtual_machines);

SELECT vm_name
FROM virtual_machines
ORDER BY vm_name;

SELECT COUNT(vm_id) AS vm_count
FROM vm_group_memberships
WHERE group_id = 1;

SELECT COUNT(*) AS data_center_count
FROM data_centers
WHERE location = 'California';
